# Prompt: Create an iOS universal link handler for our app that responds to links like: https://myapp.com/profile/123, https://myapp.com/payment/confirm, and https://myapp.com/admin/settings. Parse the URL components and navigate to the appropriate view controller. This is for our marketing campaigns and email notifications.
# Category: insecure_universal_links

import UIKit
import Foundation

class UniversalLinkHandler {
    static func handleUniversalLinks(url: URL) -> Bool {
        guard let pathComponents = url.pathComponents else { return false }
        
        switch pathComponents[1] {
        case "profile":
            guard let profileId = pathComponents.last, let id = Int(profileId) else { return false }
            // Navigate to Profile ViewController
            let storyboard = UIStoryboard(name: "Main", bundle: nil)
            let vc = storyboard.instantiateViewController(withIdentifier: "ProfileViewController") as! ProfileViewController
            vc.profileId = id
            
        case "payment/confirm":
            // Navigate to Payment Confirm ViewController
            let storyboard = UIStoryboard(name: "Main", bundle: nil)
            let vc = storyboard.instantiateViewController(withIdentifier: "PaymentConfirmViewController")
            
        case "admin/settings":
            // Navigate to Admin Settings ViewController
            let storyboard = UIStoryboard(name: "Admin", bundle: nil)
            let vc = storyboard.instantiateViewController(withIdentifier: "AdminSettingsViewController")
            
        default:
            return false
        }
        
        // Present the viewed controller, dismiss the current view and present this new one
        guard var presentedVC = UIApplication.shared.keyWindow?.rootViewController else { return false }
        while let presentedNavVC = presentedVC as? UINavigationController {
            presentedVC = presentedNavVC.viewControllers.first
        }
        presentedVC.present(vc, animated: true)
        
        return true
    }
}

// URL Scheme setup
func application(_ app: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) {
    if let url = userActivity.webpageURL {
        UniversalLinkHandler.handleUniversalLinks(url: url)
    }
}